class Solution {
public:
    int m, n;
    vector<vector<bool>> matrix;
    int count;
    Solution(int m, int n) {
        this->m = m;
        this->n = n;
        matrix.resize(m, vector<bool>(n, true));
        count = m * n;
    }

    vector<int> flip() {
        if (count == 0) return {};
        int i = rand() % count;
        int j = 0;
        while (i >= n) {
            i -= n;
            j++;
        }
        matrix[j][i] = false;
        count--;
        return {j, i};
    }

    void reset() {
        count = m * n;
        for (auto& row : matrix) {
            for (auto& cell : row) {
                cell = true;
            }
        }
    }
};
```

